    if (!suit) return null;

    if (suit === 'wind') {
      var rank = WIND_CODE_TO_RANK[rest];
      if (!rank) return null;
      return { suit: suit, rank: rank };
    }
    if (suit === 'dragon') {
      var dRank = DRAGON_CODE_TO_RANK[rest];
      if (!dRank) return null;
      return { suit: suit, rank: dRank };
    }

    var num = parseInt(rest, 10);
    if (isNaN(num)) return null;
